   152→// Initialize tables if Database is present
   153→async function bootstrapDb() {
   154→  if (!pool) return;
   155→  try {
   156→    const client = await pool.connect();
   157→    console.log('Connected to PostgreSQL successfully.');
   158→
   159→    // Create reported leads table
   160→    await client.query(`
   161→      CREATE TABLE IF NOT EXISTS leads_reporting (
   162→        id VARCHAR(100) PRIMARY KEY,
   163→        manager_name VARCHAR(255) NOT NULL,
   164→        client_name VARCHAR(255) NOT NULL,
   165→        client_phone VARCHAR(100),
   166→        amocrm_lead_id VARCHAR(255),
   167→        booking_date DATE NOT NULL,
   168→        status VARCHAR(100) NOT NULL,
   169→        deposit_required BOOLEAN DEFAULT FALSE,
   170→        deposit_amount NUMERIC(12,2) DEFAULT 0,
   171→        deposit_paid BOOLEAN DEFAULT FALSE,
   172→        comments TEXT,
   173→        created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
   174→        updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
   175→      );
   176→    `);
   177→
   178→    // Create rules table
   179→    await client.query(`
   180→      CREATE TABLE IF NOT EXISTS commission_rules (
   181→        id VARCHAR(50) PRIMARY KEY,
   182→        base_salary NUMERIC(12,2) NOT NULL,
   183→        per_booking NUMERIC(12,2) NOT NULL,
   184→        per_deposit_collected NUMERIC(12,2) NOT NULL,
   185→        per_show_up NUMERIC(12,2) NOT NULL,
   186→        target_bookings INT NOT NULL,
   187→        bonus_amount NUMERIC(12,2) NOT NULL,
   188→        updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
   189→      );
   190→    `);
   191→
   192→    // Create users table
   193→    await client.query(`
   194→      CREATE TABLE IF NOT EXISTS marketing_users (
   195→        name VARCHAR(255) PRIMARY KEY,
   196→        role VARCHAR(50) NOT NULL,
   197→        pin VARCHAR(100) NOT NULL,
   198→        department VARCHAR(255) NOT NULL,
   199→        bio TEXT,
   200→        avatar_color VARCHAR(100) NOT NULL,
   201→        status VARCHAR(50) DEFAULT 'offline',
   202→        last_active VARCHAR(100)
   203→      );
   204→    `);
   205→
   206→    // Insert default rules if not exists
   207→    const rulesCheck = await client.query('SELECT COUNT(*) FROM commission_rules');
   208→    if (parseInt(rulesCheck.rows[0].count) === 0) {
   209→      await client.query(`
   210→        INSERT INTO commission_rules (id, base_salary, per_booking, per_deposit_collected, per_show_up, target_bookings, bonus_amount)
   211→        VALUES ('default', 40000, 1000, 1500, 2000, 15, 10000)
   212→      `);
   213→    }
   214→
   215→    // Insert default users if not exists
   216→    const usersCheck = await client.query('SELECT COUNT(*) FROM marketing_users');
   217→    if (parseInt(usersCheck.rows[0].count) === 0) {
   218→      for (const u of DEFAULT_USERS) {
   219→        await client.query(`
   220→          INSERT INTO marketing_users (name, role, pin, department, bio, avatar_color, status, last_active)
   221→          VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
   222→        `, [u.name, u.role, u.pin, u.department, u.bio, u.avatarColor, u.status, u.lastActive]);
   223→      }
   224→    }
   225→
   226→    client.release();
   227→    isDbConnected = true;
   228→    dbStatus.configured = true;
   229→    dbStatus.error = '';
   230→    console.log('PostgreSQL reporting tables bootstrapped.');
   231→  } catch (err: any) {
   232→    isDbConnected = false;
   233→    dbStatus.configured = false;
   234→    dbStatus.error = `Database connection failed: ${err.message}`;
   235→    console.error('Failed to bootstrap PostgreSQL database:', err);
   236→  }
