   301→// SAVE or Update user
   302→app.post('/api/users', async (req, res) => {
   303→  const { name, role, pin, department, bio, avatarColor, status, lastActive } = req.body;
   304→  if (!name || !role || !pin) {
   305→    return res.status(400).json({ error: 'Имя, роль и пин-код обязательны' });
   306→  }
   307→
   308→  const finalAvatar = avatarColor || 'from-indigo-500 to-purple-600';
   309→  const finalDept = department || (role === 'admin' ? 'Администрация' : 'Отдел продаж');
   310→
   311→  if (pool && isDbConnected) {
   312→    try {
   313→      await pool.query(`
   314→        INSERT INTO marketing_users (name, role, pin, department, bio, avatar_color, status, last_active)
   315→        VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
   316→        ON CONFLICT (name) DO UPDATE SET
   317→          role = EXCLUDED.role,
   318→          pin = EXCLUDED.pin,
   319→          department = EXCLUDED.department,
   320→          bio = EXCLUDED.bio,
   321→          avatar_color = EXCLUDED.avatar_color,
