   325→      res.json({ success: true, name });
   326→    } catch (err: any) {
   327→      res.status(500).json({ error: 'Postgres user save failed: ' + err.message });
   328→    }
   329→  } else {
   330→    const users = readLocalUsers();
   331→    const existingIdx = users.findIndex((u: any) => u.name === name);
   332→    const updatedUser = {
   333→      name,
   334→      role,
   335→      pin,
   336→      department: finalDept,
   337→      bio: bio || '',
   338→      avatarColor: finalAvatar,
   339→      status: status || 'offline',
   340→      lastActive: lastActive || 'Не в сети'
   341→    };
   342→
   343→    if (existingIdx >= 0) {
   344→      users[existingIdx] = updatedUser;
   345→    } else {
