   371→// LOGIN WITH PIN
   372→app.post('/api/auth/login', async (req, res) => {
   373→  const { name, pin } = req.body;
   374→  if (!pin) {
   375→    return res.status(400).json({ error: 'ПИН-код обязателен' });
   376→  }
   377→
   378→  let matchedUser: any = null;
   379→  if (pool && isDbConnected) {
   380→    try {
   381→      let query = '';
   382→      let params = [];
   383→      if (name) {
   384→        query = 'SELECT * FROM marketing_users WHERE name = $1 AND pin = $2';
   385→        params = [name, pin];
   386→      } else {
   387→        query = 'SELECT * FROM marketing_users WHERE pin = $1';
   388→        params = [pin];
   389→      }
   390→      const result = await pool.query(query, params);
   391→      if (result.rows.length > 0) {
   392→        const row = result.rows[0];
   393→        matchedUser = {
   394→          name: row.name,
   395→          role: row.role,
   396→          pin: row.pin,
   397→          department: row.department,
   398→          bio: row.bio,
   399→          avatarColor: row.avatar_color,
   400→          status: 'online',
   401→          lastActive: 'В сети'
   402→        };
   403→
   404→        // Update online status in postgres
   405→        await pool.query('UPDATE marketing_users SET status = $1, last_active = $2 WHERE name = $3', ['online', 'В сети', row.name]);
   406→      }
   407→    } catch (err: any) {
   408→      console.error('Login database matching error:', err);
   409→    }
   410→  }
   411→
   412→  // Fallback if not found in Postgres or not connected
   413→  if (!matchedUser) {
   414→    const users = readLocalUsers();
