   417→    } else {
   418→      matchedUser = users.find((u: any) => u.pin === pin);
   419→    }
   420→
   421→    if (matchedUser) {
   422→      // Update status in local fallback
   423→      const uIdx = users.findIndex((u: any) => u.name === matchedUser.name);
   424→      if (uIdx >= 0) {
   425→        users[uIdx].status = 'online';
   426→        users[uIdx].lastActive = 'В сети';
   427→        writeLocalUsers(users);
   428→      }
   429→    }
   430→  }
   431→
   432→  if (matchedUser) {
   433→    res.json({ success: true, user: matchedUser });
   434→  } else {
   435→    res.status(401).json({ success: false, error: 'Введен неверный ПИН-код' });
   436→  }
   437→});
