import fs from 'fs';
import path from 'path';

const DATA_DIR = path.join(process.cwd(), 'data');
if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });

export const LEADS_FILE = path.join(DATA_DIR, 'leads.json');
export const RULES_FILE = path.join(DATA_DIR, 'rules.json');
export const USERS_FILE = path.join(DATA_DIR, 'users.json');

export const DEFAULT_RULES = {
  baseSalary: 40000,
  perBooking: 1000,
  perDepositCollected: 1500,
  perShowUp: 2000,
  targetBookings: 15,
  bonusAmount: 10000,
};

export const DEFAULT_USERS = [
  { name: 'Александр Г.', role: 'admin', pin: '1111', department: 'Руководитель', bio: 'Управление KPI, структурой и бюджетом', avatarColor: 'from-indigo-500 to-indigo-700', status: 'online', lastActive: 'В сети' },
  { name: 'Мария С.', role: 'admin', pin: '2222', department: 'Тех. Администратор', bio: 'Аудит и верификация AmoCRM статусов', avatarColor: 'from-purple-500 to-pink-500', status: 'online', lastActive: '10 мин назад' },
  { name: 'Алина К.', role: 'manager', pin: '3333', department: 'Старший лид-менеджер', bio: 'Специалист по работе с клиентами повышенной категории', avatarColor: 'from-emerald-400 to-teal-500', status: 'online', lastActive: 'В сети' },
  { name: 'Иван П.', role: 'manager', pin: '4444', department: 'Лид-менеджер', bio: 'Фокус на закрытии предоплат и визитов', avatarColor: 'from-blue-500 to-indigo-500', status: 'offline', lastActive: '1 час назад' },
  { name: 'Маргарита Д.', role: 'manager', pin: '5555', department: 'Лид-менеджер', bio: 'Работа с повторными контактами и холодным трафиком', avatarColor: 'from-amber-400 to-orange-500', status: 'online', lastActive: '3 мин назад' },
  { name: 'Сергей В.', role: 'manager', pin: '6666', department: 'Лид-менеджер', bio: 'Ведение сделок со сложными условиями финансирования', avatarColor: 'from-cyan-400 to-blue-500', status: 'online', lastActive: 'В сети' },
];

if (!fs.existsSync(LEADS_FILE)) fs.writeFileSync(LEADS_FILE, '[]', 'utf-8');
if (!fs.existsSync(RULES_FILE)) fs.writeFileSync(RULES_FILE, JSON.stringify(DEFAULT_RULES, null, 2), 'utf-8');
if (!fs.existsSync(USERS_FILE)) fs.writeFileSync(USERS_FILE, JSON.stringify(DEFAULT_USERS, null, 2), 'utf-8');

function safeRead<T>(file: string, fallback: T): T {
  try { return JSON.parse(fs.readFileSync(file, 'utf-8')); } catch { return fallback; }
}

export const readLocalLeads  = (): any[]  => safeRead(LEADS_FILE, []);
export const writeLocalLeads = (data: any) => fs.writeFileSync(LEADS_FILE, JSON.stringify(data, null, 2), 'utf-8');

export const readLocalRules  = () => safeRead(RULES_FILE, DEFAULT_RULES);
export const writeLocalRules = (rules: any) => fs.writeFileSync(RULES_FILE, JSON.stringify(rules, null, 2), 'utf-8');

export const readLocalUsers  = (): any[] => safeRead(USERS_FILE, DEFAULT_USERS);
export const writeLocalUsers = (users: any) => fs.writeFileSync(USERS_FILE, JSON.stringify(users, null, 2), 'utf-8');

import pg from 'pg';
import dotenv from 'dotenv';
import { DEFAULT_RULES, DEFAULT_USERS } from './localFallback';

dotenv.config();

export const db = {
  pool: null as pg.Pool | null,
  isConnected: false,
  status: {
    provider: 'local' as 'local' | 'postgres',
    configured: false,
    error: '',
    connectionInfo: '',
    tableName: 'leads_reporting',
  },
};

const hasPgUrl = !!process.env.DATABASE_URL;
const hasPgIndividual = !!(process.env.PGHOST && process.env.PGUSER && process.env.PGPASSWORD && process.env.PGDATABASE);

if (hasPgUrl || hasPgIndividual) {
  try {
    const config = hasPgUrl
      ? { connectionString: process.env.DATABASE_URL, ssl: { rejectUnauthorized: false }, connectionTimeoutMillis: 3000 }
      : {
          host: process.env.PGHOST,
          port: process.env.PGPORT ? parseInt(process.env.PGPORT) : 5432,
          user: process.env.PGUSER,
          password: process.env.PGPASSWORD,
          database: process.env.PGDATABASE,
          ssl: { rejectUnauthorized: false },
          connectionTimeoutMillis: 3000,
        };
    db.pool = new pg.Pool(config as any);
    db.status.provider = 'postgres';
    db.status.connectionInfo = hasPgUrl
      ? process.env.DATABASE_URL!.split('@')[1] || 'PostgreSQL'
      : `${process.env.PGHOST}:${process.env.PGPORT || 5432}/${process.env.PGDATABASE}`;
  } catch (err: any) {
    db.status.error = err.message || 'Failed to initialize Postgres pool';
    console.error('[DB] Pool init error:', err);
  }
}

export async function bootstrapDb(): Promise<void> {
  if (!db.pool) return;
  try {
    const client = await db.pool.connect();
    console.log('[DB] Connected to PostgreSQL.');

    await client.query(`
      CREATE TABLE IF NOT EXISTS leads_reporting (
        id VARCHAR(100) PRIMARY KEY,
        manager_name VARCHAR(255) NOT NULL,
        client_name VARCHAR(255) NOT NULL,
        client_phone VARCHAR(100),
        amocrm_lead_id VARCHAR(255),
        booking_date DATE NOT NULL,
        status VARCHAR(100) NOT NULL,
        deposit_required BOOLEAN DEFAULT FALSE,
        deposit_amount NUMERIC(12,2) DEFAULT 0,
        deposit_paid BOOLEAN DEFAULT FALSE,
        comments TEXT,
        created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
      );
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS commission_rules (
        id VARCHAR(50) PRIMARY KEY,
        base_salary NUMERIC(12,2) NOT NULL,
        per_booking NUMERIC(12,2) NOT NULL,
        per_deposit_collected NUMERIC(12,2) NOT NULL,
        per_show_up NUMERIC(12,2) NOT NULL,
        target_bookings INT NOT NULL,
        bonus_amount NUMERIC(12,2) NOT NULL,
        updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
      );
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS marketing_users (
        name VARCHAR(255) PRIMARY KEY,
        role VARCHAR(50) NOT NULL,
        pin VARCHAR(100) NOT NULL,
        department VARCHAR(255) NOT NULL,
        bio TEXT,
        avatar_color VARCHAR(100) NOT NULL,
        status VARCHAR(50) DEFAULT 'offline',
        last_active VARCHAR(100)
      );
    `);

    const rulesCount = await client.query('SELECT COUNT(*) FROM commission_rules');
    if (parseInt(rulesCount.rows[0].count) === 0) {
      await client.query(
        `INSERT INTO commission_rules (id, base_salary, per_booking, per_deposit_collected, per_show_up, target_bookings, bonus_amount)
         VALUES ('default', $1, $2, $3, $4, $5, $6)`,
        [DEFAULT_RULES.baseSalary, DEFAULT_RULES.perBooking, DEFAULT_RULES.perDepositCollected,
         DEFAULT_RULES.perShowUp, DEFAULT_RULES.targetBookings, DEFAULT_RULES.bonusAmount]
      );
    }

    const usersCount = await client.query('SELECT COUNT(*) FROM marketing_users');
    if (parseInt(usersCount.rows[0].count) === 0) {
      for (const u of DEFAULT_USERS) {
        await client.query(
          `INSERT INTO marketing_users (name, role, pin, department, bio, avatar_color, status, last_active)
           VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
          [u.name, u.role, u.pin, u.department, u.bio, u.avatarColor, u.status, u.lastActive]
        );
      }
    }

    client.release();
    db.isConnected = true;
    db.status.configured = true;
    db.status.error = '';
    console.log('[DB] Tables bootstrapped successfully.');
  } catch (err: any) {
    db.isConnected = false;
    db.status.configured = false;
    db.status.error = `Connection failed: ${err.message}`;
    console.error('[DB] Bootstrap failed:', err);
  }
}

import { Router } from 'express';
import { db } from '../db';
import { readLocalUsers, writeLocalUsers } from '../localFallback';

const router = Router();

// In-memory rate limiter: max 10 attempts per IP per minute
// NOTE: For multi-instance deployments, replace with Redis-backed rate limiting
const attempts = new Map<string, { count: number; resetAt: number }>();

function checkRateLimit(ip: string): boolean {
  const now = Date.now();
  const entry = attempts.get(ip);
  if (!entry || entry.resetAt < now) {
    attempts.set(ip, { count: 1, resetAt: now + 60_000 });
    return true;
  }
  if (entry.count >= 10) return false;
  entry.count++;
  return true;
}

// POST /api/auth/login
router.post('/login', async (req, res) => {
  const ip = req.ip || req.socket.remoteAddress || 'unknown';
  if (!checkRateLimit(ip)) {
    return res.status(429).json({ success: false, error: 'Слишком много попыток. Подождите минуту.' });
  }

  const { name, pin } = req.body;
  if (!pin) {
    return res.status(400).json({ success: false, error: 'ПИН-код обязателен' });
  }

  let matchedUser: any = null;

  if (db.pool && db.isConnected) {
    try {
      const query = name
        ? 'SELECT * FROM marketing_users WHERE name = $1 AND pin = $2'
        : 'SELECT * FROM marketing_users WHERE pin = $1';
      const params = name ? [name, pin] : [pin];
      const result = await db.pool.query(query, params);

      if (result.rows.length > 0) {
        const row = result.rows[0];
        matchedUser = {
          name: row.name, role: row.role, pin: row.pin,
          department: row.department, bio: row.bio,
          avatarColor: row.avatar_color, status: 'online', lastActive: 'В сети',
        };
        await db.pool.query(
          'UPDATE marketing_users SET status = $1, last_active = $2 WHERE name = $3',
          ['online', 'В сети', row.name]
        );
      }
    } catch (err) {
      console.error('[Auth] DB login error:', err);
    }
  }

  if (!matchedUser) {
    const users = readLocalUsers();
    matchedUser = name
      ? users.find((u: any) => u.name === name && u.pin === pin)
      : users.find((u: any) => u.pin === pin);

    if (matchedUser) {
      const idx = users.findIndex((u: any) => u.name === matchedUser.name);
      if (idx >= 0) {
        users[idx].status = 'online';
        users[idx].lastActive = 'В сети';
        writeLocalUsers(users);
      }
    }
  }

  if (matchedUser) {
    return res.json({ success: true, user: matchedUser });
  }
  res.status(401).json({ success: false, error: 'Неверный ПИН-код' });
});

// POST /api/auth/logout
router.post('/logout', async (req, res) => {
  const { name } = req.body;
  if (!name) return res.json({ success: true });

  const lastActive = new Date().toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' }) + ' назад';

  if (db.pool && db.isConnected) {
    try {
      await db.pool.query(
        'UPDATE marketing_users SET status = $1, last_active = $2 WHERE name = $3',
        ['offline', lastActive, name]
      );
    } catch (err) {
      console.error('[Auth] DB logout error:', err);
    }
  } else {
    const users = readLocalUsers();
    const idx = users.findIndex((u: any) => u.name === name);
    if (idx >= 0) {
      users[idx].status = 'offline';
      users[idx].lastActive = lastActive;
      writeLocalUsers(users);
    }
  }
  res.json({ success: true });
});

