interface LoginPageProps {
  onLogin: (user: StaffMember) => void;
}

export default function LoginPage({ onLogin }: LoginPageProps) {
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!pin.trim()) { setError('Пожалуйста, введите ваш ПИН-код'); return; }
    setError('');
    setLoading(true);
    try {
      const data = await api.auth.login(pin);
      if (data.success) onLogin(data.user);
    } catch (err) {
      if (err instanceof ApiError && err.status === 429) {
        setError(err.message);
      } else if (err instanceof ApiError && err.status === 401) {
        setError('Введён неверный ПИН-код');
      } else {
        setError('Сбой авторизации. Проверьте подключение.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-50/60 via-slate-50/90 to-indigo-100/25 flex items-center justify-center p-6 font-sans select-none antialiased">
      <div className="w-full max-w-sm">
        <div className="spatial-glass rounded-3xl p-8 shadow-md space-y-6 relative overflow-hidden border border-indigo-100/50">
          <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-indigo-600 to-violet-600 animate-pulse" />

