            <h2 className="text-xl font-display font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-violet-700 tracking-tight">
              «Виви Маркетинг»
            </h2>
            <p className="text-[8.5px] text-neutral-400 uppercase font-bold tracking-widest leading-none">
              Система KPI и учёта записей
            </p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {error && (
              <div className="py-2.5 px-3 bg-rose-50 border border-rose-200 text-rose-700 rounded-xl text-center text-[10.5px] font-bold tracking-wider uppercase leading-relaxed">
                {error}
              </div>
            )}

            <div className="space-y-2">
              <label className="block text-[8px] uppercase font-extrabold tracking-widest text-neutral-400">
                Введите ваш рабочий ПИН-код
              </label>
              <input
                type="password"
                maxLength={6}
                value={pin}
                onChange={(e) => setPin(e.target.value.replace(/\D/g, ''))}
