                className="w-full text-center tracking-[0.5em] font-extrabold text-lg py-3 bg-white/70 border border-neutral-200 rounded-xl text-neutral-950 focus:outline-hidden focus:border-indigo-500 placeholder-neutral-300 transition-all shadow-sm"
              />
            </div>

            <button
