              className="w-full py-3.5 bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 disabled:from-neutral-200 disabled:to-neutral-300 disabled:text-neutral-400 text-white font-extrabold uppercase tracking-widest text-[9.5px] rounded-xl transition-all duration-300 cursor-pointer flex items-center justify-center gap-1.5 shadow-[0_4px_18px_-4px_rgba(79,70,229,0.4)] hover:scale-[1.01] active:scale-95"
            >
