import express from 'express';
import path from 'path';
import dotenv from 'dotenv';
import { createServer as createViteServer } from 'vite';

import { bootstrapDb, db } from './server/db';
import authRouter  from './server/routes/auth';
import leadsRouter from './server/routes/leads';
import rulesRouter from './server/routes/rules';
import usersRouter from './server/routes/users';

dotenv.config();

const app  = express();
const PORT = parseInt(process.env.PORT || '5000');

app.use(express.json());

app.use('/api/auth',  authRouter);
app.use('/api/leads', leadsRouter);
app.use('/api/rules', rulesRouter);
app.use('/api/users', usersRouter);

app.get('/api/db-status', (_req, res) => {
  res.json({
    provider:       db.status.provider,
    connected:      db.isConnected,
    configured:     db.status.configured,
    connectionInfo: db.status.connectionInfo,
    tableName:      db.status.tableName,
    error:          db.status.error || null,
  });
});

async function startServer() {
  await bootstrapDb();

  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (_req, res) => res.sendFile(path.join(distPath, 'index.html')));
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'motion/react';

import { useData }           from './hooks/useData';
import { api }               from './api/client';
import type { LeadReport, CommissionRules, StaffMember } from './types';

import LoginPage             from './pages/LoginPage';
import DashboardPage         from './pages/DashboardPage';
import LeadsPage             from './pages/LeadsPage';
import StaffDirectoryPage    from './pages/StaffDirectoryPage';
import UserManagementPage    from './pages/UserManagementPage';
import Sidebar               from './components/Sidebar';
import Header                from './components/Header';
import SalarySummary         from './components/SalarySummary';

type ActiveMenu = 'dashboard' | 'leads' | 'salary' | 'staff_directory' | 'user_management';

const SESSION_KEY = 'vivi_marketing_session';

const PAGE_TRANSITION = {
  initial:    { opacity: 0, y: 12 },
  animate:    { opacity: 1, y: 0 },
  exit:       { opacity: 0, y: -12 },
  transition: { duration: 0.25, ease: [0.16, 1, 0.3, 1] },
};

export default function App() {
  const { leads, rules, allUsers, loading, refreshLeads, refreshRules, refreshUsers, initialize } = useData();

  const [currentUser, setCurrentUser]   = useState<StaffMember | null>(null);
  const [isAuthenticated, setAuth]      = useState(false);
  const [activeMenu, setActiveMenu]     = useState<ActiveMenu>('dashboard');
  const [isFormOpen, setIsFormOpen]     = useState(false);
  const [editingLead, setEditingLead]   = useState<LeadReport | null>(null);

  // Initial load + restore session
  useEffect(() => {
    initialize().then(() => {
      try {
        const stored = localStorage.getItem(SESSION_KEY);
        if (stored) {
          const user = JSON.parse(stored) as StaffMember;
          setCurrentUser(user);
          setAuth(true);
        }
      } catch {
        localStorage.removeItem(SESSION_KEY);
      }
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Light polling for leads only when authenticated and tab is visible
  useEffect(() => {
    if (!isAuthenticated) return;
    const id = setInterval(() => {
      if (document.visibilityState === 'visible') refreshLeads();
    }, 30_000);
    return () => clearInterval(id);
  }, [isAuthenticated, refreshLeads]);

  const handleLogin = useCallback((user: StaffMember) => {
    setCurrentUser(user);
    setAuth(true);
    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    // Refresh all data right after login to pick up any server-side changes
    Promise.all([refreshLeads(), refreshRules(), refreshUsers()]);
  }, [refreshLeads, refreshRules, refreshUsers]);

  const handleLogout = useCallback(async () => {
    if (currentUser) {
      api.auth.logout(currentUser.name).catch(() => {});
    }
    setAuth(false);
    setCurrentUser(null);
    setActiveMenu('dashboard');
    setIsFormOpen(false);
    setEditingLead(null);
    localStorage.removeItem(SESSION_KEY);
  }, [currentUser]);

  const handleSaveLead = useCallback(async (lead: LeadReport): Promise<boolean> => {
    try {
      await api.leads.save(lead);
      await refreshLeads();
      setIsFormOpen(false);
      setEditingLead(null);
      return true;
    } catch (err) {
      console.error('[App] Save lead error:', err);
      return false;
    }
  }, [refreshLeads]);

  const handleDeleteLead = useCallback(async (id: string): Promise<void> => {
    try {
      await api.leads.delete(id);
      await refreshLeads();
    } catch (err) {
      console.error('[App] Delete lead error:', err);
    }
  }, [refreshLeads]);

  const handleSaveRules = useCallback(async (newRules: CommissionRules): Promise<boolean> => {
    try {
      await api.rules.save(newRules);
      await refreshRules();
      return true;
    } catch (err) {
      console.error('[App] Save rules error:', err);
      return false;
    }
  }, [refreshRules]);

  const handleEditLead = useCallback((lead: LeadReport) => {
    setEditingLead(lead);
    setIsFormOpen(true);
    setActiveMenu('leads');
  }, []);

  const navigate = useCallback((menu: ActiveMenu) => {
    setActiveMenu(menu);
    if (menu !== 'leads') { setIsFormOpen(false); setEditingLead(null); }
  }, []);

  const toggleForm = useCallback(() => {
    setEditingLead(null);
    setIsFormOpen(open => !open);
    setActiveMenu('leads');
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-50/60 via-slate-50 to-indigo-100/25 flex items-center justify-center">
        <div className="text-center space-y-4">
          <div className="w-8 h-8 border-2 border-indigo-600/30 border-t-indigo-600 rounded-full animate-spin mx-auto" />
          <p className="text-[10px] text-neutral-400 font-bold uppercase tracking-widest">Загрузка системы...</p>
        </div>
      </div>
    );
  }

  if (!isAuthenticated || !currentUser) {
    return <LoginPage onLogin={handleLogin} />;
  }

  const myLeadsCount = currentUser.role === 'admin'
    ? leads.length
    : leads.filter(l => l.managerName === currentUser.name).length;

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50/80 via-indigo-50/20 to-slate-100/60 text-slate-800 flex flex-col lg:flex-row antialiased font-sans">
      <Sidebar
        currentUser={currentUser}
        activeMenu={activeMenu}
        onNavigate={navigate}
        totalLeadsCount={myLeadsCount}
        totalUsersCount={allUsers.length}
        onLogout={handleLogout}
      />

      <main className="flex-1 flex flex-col min-w-0 z-10 relative">
        <Header
          activeMenu={activeMenu}
          isFormOpen={isFormOpen}
          onToggleForm={toggleForm}
        />

        <div className="flex-1 p-5 lg:p-8 max-w-7xl mx-auto w-full">
          <AnimatePresence mode="wait">
            {activeMenu === 'dashboard' && (
              <motion.div key="dashboard" {...PAGE_TRANSITION}>
                <DashboardPage
                  leads={leads}
                  rules={rules}
                  allUsers={allUsers}
                  currentUser={currentUser}
                  onNavigate={navigate}
                />
              </motion.div>
            )}

            {activeMenu === 'leads' && (
              <motion.div key="leads" {...PAGE_TRANSITION}>
                <LeadsPage
                  leads={leads}
                  currentUser={currentUser}
                  allUsers={allUsers}
                  isFormOpen={isFormOpen}
                  editingLead={editingLead}
                  onSaveLead={handleSaveLead}
                  onDeleteLead={handleDeleteLead}
                  onEditLead={handleEditLead}
                  onCloseForm={() => { setIsFormOpen(false); setEditingLead(null); }}
                />
              </motion.div>
            )}

            {activeMenu === 'salary' && (
              <motion.div key="salary" {...PAGE_TRANSITION}>
                <SalarySummary
                  leads={leads}
                  rules={rules}
                  onSaveRules={handleSaveRules}
                  currentUserRole={currentUser.role}
                  currentManagerName={currentUser.name}
                />
              </motion.div>
            )}

            {activeMenu === 'staff_directory' && (
              <motion.div key="staff" {...PAGE_TRANSITION}>
                <StaffDirectoryPage allUsers={allUsers} leads={leads} />
              </motion.div>
            )}

            {activeMenu === 'user_management' && currentUser.role === 'admin' && (
              <motion.div key="users" {...PAGE_TRANSITION}>
                <UserManagementPage
                  allUsers={allUsers}
                  currentUserName={currentUser.name}
                  onRefresh={refreshUsers}
                />
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { Delete, CornerDownLeft, Sparkles, Shield } from 'lucide-react';
import { api, ApiError } from '../api/client';
import type { StaffMember } from '../types';

const PAD: string[][] = [
  ['1', '2', '3'],
  ['4', '5', '6'],
  ['7', '8', '9'],
  ['del', '0', 'enter'],
];

const PIN_LENGTH = 6;

export default function LoginPage({ onLogin }: { onLogin: (user: StaffMember) => void }) {
  const [pin, setPin]           = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [shake, setShake]       = useState(false);
  const rootRef                 = useRef<HTMLDivElement>(null);

  useEffect(() => { rootRef.current?.focus(); }, []);

  const submit = useCallback(async (currentPin: string) => {
    if (currentPin.length < 4 || loading) return;
    setError('');
    setLoading(true);
    try {
      const data = await api.auth.login(currentPin);
      if (data.success) onLogin(data.user);
    } catch (err) {
      setPin('');
      setShake(true);
      setTimeout(() => setShake(false), 500);
      if (err instanceof ApiError && err.status === 429) {
        setError(err.message);
      } else {
        setError('Неверный ПИН-код. Попробуйте ещё раз.');
      }
    } finally {
      setLoading(false);
    }
  }, [loading, onLogin]);

  const pressKey = useCallback((key: string) => {
    if (loading) return;
    if (key === 'del') {
      setPin(p => p.slice(0, -1));
      setError('');
    } else if (key === 'enter') {
      submit(pin);
    } else {
      setPin(p => {
        if (p.length >= PIN_LENGTH) return p;
        const next = p + key;
        return next;
      });
      setError('');
    }
  }, [loading, pin, submit]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key >= '0' && e.key <= '9') { e.preventDefault(); pressKey(e.key); }
    else if (e.key === 'Backspace')    { e.preventDefault(); pressKey('del'); }
    else if (e.key === 'Enter')        { e.preventDefault(); pressKey('enter'); }
  }, [pressKey]);

  return (
    <div
      ref={rootRef}
      tabIndex={0}
      onKeyDown={handleKeyDown}
      className="min-h-screen bg-slate-950 flex items-center justify-center p-4 overflow-hidden relative focus:outline-none select-none antialiased"
    >
      {/* Ambient background blobs */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        <div className="absolute top-1/3 left-1/4 w-[600px] h-[600px] rounded-full bg-indigo-900/25 blur-[140px]" />
        <div className="absolute bottom-1/4 right-1/4 w-[500px] h-[500px] rounded-full bg-violet-900/20 blur-[120px]" />
        <div className="absolute top-2/3 left-1/2 w-[350px] h-[350px] rounded-full bg-indigo-800/15 blur-[100px]" />
        {/* Subtle grid */}
        <div className="absolute inset-0 opacity-[0.03]"
          style={{ backgroundImage: 'linear-gradient(rgba(255,255,255,.5) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,.5) 1px, transparent 1px)', backgroundSize: '40px 40px' }} />
      </div>

      <motion.div
        initial={{ opacity: 0, y: 24, scale: 0.97 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ duration: 0.55, ease: [0.16, 1, 0.3, 1] }}
        className="relative z-10 w-full max-w-[320px]"
      >
        {/* Brand header */}
        <div className="text-center mb-8 space-y-3">
          <motion.div
            initial={{ opacity: 0, y: -8 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="inline-flex items-center gap-2 bg-white/[0.06] border border-white/[0.08] px-3.5 py-1.5 rounded-full"
          >
            <Sparkles className="w-3 h-3 text-violet-400" />
            <span className="text-[8.5px] text-white/40 font-bold uppercase tracking-widest">KPI Система</span>
          </motion.div>

          <motion.h1
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.15 }}
            className="text-[26px] font-display font-black text-white leading-tight tracking-tight"
          >
            «Виви Маркетинг»
          </motion.h1>

          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.2 }}
            className="text-[9px] text-white/25 uppercase tracking-[0.2em] font-medium"
          >
            Учёт записей и расчёт комиссий
          </motion.p>
        </div>

        {/* Main card */}
        <motion.div
          animate={shake ? { x: [-8, 8, -6, 6, -3, 3, 0] } : {}}
          transition={{ duration: 0.4 }}
          className="bg-white/[0.04] backdrop-blur-2xl border border-white/[0.07] rounded-3xl p-6 shadow-[0_40px_80px_rgba(0,0,0,0.6)] space-y-5"
        >
          {/* PIN display */}
          <div className="space-y-3.5">
            <div className="flex items-center justify-between text-[8.5px] text-white/25 font-bold uppercase tracking-widest">
              <span>Ваш ПИН-код</span>
              <div className="flex items-center gap-1">
                <Shield className="w-2.5 h-2.5 text-emerald-500/60" />
                <span className="text-emerald-500/50">Защищённый вход</span>
              </div>
            </div>

            <div className="flex items-center justify-center gap-3 py-2">
              {Array.from({ length: PIN_LENGTH }).map((_, i) => (
                <motion.div
                  key={i}
                  animate={i < pin.length ? { scale: [1, 1.25, 1] } : {}}
                  transition={{ duration: 0.18 }}
                  className={`w-3.5 h-3.5 rounded-full transition-all duration-200 ${
                    i < pin.length
                      ? 'bg-violet-400 shadow-[0_0_10px_3px_rgba(167,139,250,0.45)] scale-110'
                      : 'border-2 border-white/15 bg-transparent'
                  }`}
                />
              ))}
            </div>
          </div>

          {/* Error message */}
          <AnimatePresence>
            {error && (
              <motion.div
                initial={{ opacity: 0, height: 0, y: -4 }}
                animate={{ opacity: 1, height: 'auto', y: 0 }}
                exit={{ opacity: 0, height: 0 }}
                transition={{ duration: 0.2 }}
                className="overflow-hidden"
              >
                <div className="py-2.5 px-3.5 bg-red-500/10 border border-red-500/20 rounded-xl text-center text-[10.5px] text-red-300/90 font-bold leading-relaxed">
                  {error}
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Numeric pad */}
          <div className="grid grid-cols-3 gap-2">
            {PAD.flat().map(key => {
              const isDigit   = key !== 'del' && key !== 'enter';
              const isEnter   = key === 'enter';
              const isDel     = key === 'del';
              const enterReady = pin.length >= 4 && !loading;
              const disabled  = loading || (isEnter && pin.length < 4);

              return (
                <motion.button
                  key={key}
                  whileTap={disabled ? {} : { scale: 0.88 }}
                  onClick={() => pressKey(key)}
                  disabled={disabled}
                  className={[
                    'relative h-[54px] rounded-2xl font-bold text-base transition-all duration-150 cursor-pointer overflow-hidden',
                    'focus:outline-none',
                    isDigit  && 'bg-white/[0.06] text-white hover:bg-white/[0.12] active:bg-white/[0.18] border border-white/[0.05] hover:border-white/[0.12] text-lg',
