                    isEnter && !enterReady && 'bg-white/[0.03] text-white/20 border border-white/[0.04] cursor-not-allowed',
                    isEnter &&  enterReady && 'bg-gradient-to-br from-violet-600/60 to-indigo-600/60 hover:from-violet-500/70 hover:to-indigo-500/70 text-violet-100 border border-violet-400/20 shadow-[0_4px_20px_rgba(139,92,246,0.3)]',
                  ].filter(Boolean).join(' ')}
                >
                  {isDel
                    ? <Delete className="w-4 h-4 mx-auto" />
                    : isEnter
                      ? loading
                        ? <span className="w-4 h-4 border-2 border-violet-300/30 border-t-violet-300/80 rounded-full animate-spin mx-auto block" />
                        : <CornerDownLeft className="w-4.5 h-4.5 mx-auto" />
                      : key}
                </motion.button>
              );
            })}
          </div>
        </motion.div>

        {/* Footer */}
        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.4 }}
          className="text-center text-[8.5px] text-white/15 mt-6 font-medium tracking-wide"
        >
          Цифры клавиатуры и «Enter» тоже работают
        </motion.p>
      </motion.div>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
