            <div
              className="flex items-center justify-center gap-4 py-3 cursor-text"
              onClick={() => inputRef.current?.focus()}
            >
              {Array.from({ length: PIN_LENGTH }).map((_, i) => (
                <motion.div
                  key={i}
                  animate={i === pin.length - 1 ? { scale: [1, 1.35, 1] } : {}}
                  transition={{ duration: 0.2 }}
                  className={`w-4 h-4 rounded-full transition-all duration-200 ${
                    i < pin.length
                      ? 'bg-gradient-to-br from-indigo-500 to-violet-600 shadow-[0_0_10px_rgba(99,102,241,0.45)]'
                      : i === pin.length
                        ? 'border-2 border-indigo-400/60 bg-indigo-50/60 scale-110'
