            {error && (
              <motion.div
                initial={{ opacity: 0, y: -6 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                className="py-2.5 px-4 bg-rose-50 border border-rose-200/60 rounded-xl text-center text-[10.5px] font-bold text-rose-600 uppercase tracking-wide"
              >
                {error}
              </motion.div>
            )}
          </AnimatePresence>

          {/* Submit */}
          <button
            type="submit"
            disabled={pin.length < 4 || loading}
            className="w-full py-4 bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 disabled:from-neutral-200 disabled:to-neutral-300 disabled:text-neutral-400 disabled:cursor-not-allowed text-white font-extrabold uppercase tracking-widest text-[10px] rounded-2xl transition-all duration-300 cursor-pointer shadow-[0_4px_20px_rgba(99,102,241,0.35)] hover:shadow-[0_6px_28px_rgba(99,102,241,0.5)] hover:scale-[1.01] active:scale-95 flex items-center justify-center gap-2"
