                  animate={filled && i === pin.length - 1
                    ? { scale: [1, 1.5, 1] }
                    : {}}
                  transition={{ duration: 0.2, ease: 'easeOut' }}
                  className={[
                    'rounded-full transition-all duration-200',
                    filled  ? 'w-[22px] h-[22px] bg-indigo-600 shadow-[0_0_16px_rgba(99,102,241,0.5)]'
                    : current ? 'w-[22px] h-[22px] border-[2.5px] border-indigo-400 bg-indigo-50 animate-pulse'
                    : 'w-[18px] h-[18px] bg-neutral-200',
                  ].join(' ')}
                />
              );
            })}
          </div>

          {/* Error */}
          <AnimatePresence>
            {error && (
              <motion.p
                initial={{ opacity: 0, y: -8 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                className="-mt-4 text-[11px] font-bold text-rose-500 uppercase tracking-widest text-center"
              >
                {error}
              </motion.p>
            )}
          </AnimatePresence>

          {/* Button */}
          <button
            onClick={submit}
            disabled={pin.length < 4 || loading}
            className="w-full h-[52px] rounded-2xl font-bold text-[11px] uppercase tracking-[0.18em] transition-all duration-200 cursor-pointer
              bg-indigo-600 text-white shadow-[0_4px_22px_rgba(99,102,241,0.45)]
              hover:bg-indigo-500 hover:shadow-[0_8px_32px_rgba(99,102,241,0.55)] hover:-translate-y-0.5
              active:translate-y-0 active:bg-indigo-700
              disabled:bg-neutral-100 disabled:text-neutral-350 disabled:shadow-none disabled:cursor-not-allowed disabled:translate-y-0
              flex items-center justify-center gap-2"
          >
            {loading
              ? <><span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />Проверка…</>
              : 'Войти'}
          </button>
        </motion.div>
      </motion.div>
    </div>
  );
}
